head.script:
const initMYCRedirect = () => {
  try {
    const isSignedOn = /isSignedOn=true/.test(document.cookie);
    if (isSignedOn) {
      const isMYCPilotUsr = /myChartPilotUser=true/.test(document.cookie);
      const mycURLDOM = document.querySelector("meta[name='myc:url']");
      const mycUrl = mycURLDOM?.getAttribute('content');
      console.log('[initMYCRedirect]: Checking cookie MYC ..');
      if (isMYCPilotUsr && mycUrl) {
        console.log('[initMYCRedirect]: Redirecting to MYC Page..');
        redirectToNewURL(mycUrl);
      }
    }
  } catch (err) {
    console.log('[initMYCRedirect]: Something went wrong initMYCRedirect', err);
  }
}


const initWebPivotRedirect = () => {
  try {
    const isSignedOn = /isSignedOn=true/.test(document.cookie);
    if (!isSignedOn) return;

    const webPivotUser = /webPivotUser=true/.test(document.cookie);
    if (!webPivotUser) return;

    console.log('[Web Pivot]: Checking Web Pivot logic...');

    const hostDomain = window.location.origin;
    const relativeUrl = window.location.href.replace(hostDomain, '');

    const disableWPRedirect = document
      .querySelector("meta[name='disableWPRedirect']")
      ?.getAttribute('content') === 'true';

    const webpivotUrl = document
      .querySelector("meta[name='webpivotUrl']")
      ?.getAttribute('content')
      ?.trim();

    const mycUrl = document
      .querySelector("meta[name='myc:url']")
      ?.getAttribute('content');

    const isInEpicIframe = window.parent !== window.self;
    const isMobileWeb = isMobileWebView();

    if (disableWPRedirect) {
      console.log('[Web Pivot]: Web Pivot DISABLE detected, skipping redirect.');
      return;
    }

    if (isMobileWeb) {
      console.log('[Web Pivot]: Mobile WebView detected, skipping redirect.');
      return;
    }

    if (!mycUrl && !webpivotUrl) {
      if (isInEpicIframe) {
        console.log('[Web Pivot]: Epic MyChart iframe detected, skipping redirect.');
        setEpicMychartFlag();
        updateWebPivotContent();
        return;
      }
      const fallbackUrl = '/mc/myc-link?relay=url%3D';
      const destinationUrl = hostDomain + fallbackUrl + encodeURIComponent(relativeUrl);
      console.log('[Web Pivot]: No MYC or WebPivot URL authored — applying fallback redirect.');
      redirectToNewURL(destinationUrl);
      return;
    }

    if (webpivotUrl) {
      if (isInEpicIframe) {
        console.log('[Web Pivot]: Epic MyChart iframe detected, skipping redirect.');
        setEpicMychartFlag();
        updateWebPivotContent();
        return;
      }
      const destinationUrl = hostDomain + webpivotUrl;
      console.log('[Web Pivot]: Redirecting using authored WebPivot URL.');
      redirectToNewURL(destinationUrl);
    }

  } catch (err) {
    console.error('[Web Pivot]: Error in initWebPivotRedirect', err);
  }
};

const setEpicMychartFlag = () => {
  if (!sessionStorage.getItem('isEpicMychartPage')) {
    sessionStorage.setItem('isEpicMychartPage', 'true');
  }
}

const isMobileWebView = () => {
  try {
    const url = window.location.href;
    return url.includes('.mobile.html');
  } catch (e) {
    console.error('[Web Pivot]: Error while detecting mobile WebView.', e);
    return false;
  }
};

const redirectToNewURL = (destUrl) => {
  if (destUrl != window.location.href) {
    console.log("[Web Pivot]: finalDestUrl: ", destUrl);
    window.location.href = destUrl;
  }
}

const hideProxyPicker = () => {
  try {
    const proxyPicker = document.querySelector("#proxy-picker-container");
    if (proxyPicker) {
      proxyPicker.style.display = 'none';
      console.log('[Web Pivot]: Proxy Picker hidden for Epic iframe.');
    }
  } catch (e) {
    console.error('[Web Pivot]: Error while disabling Proxy Picker.', e);
  }
}

const hideKPHeaderFooter = () => {
  try {
    const kpHeader = document.querySelector("#kp-header");
    const kpFooter = document.querySelector(".gs-footer");
    const kpGlblFooter = document.querySelector(".kp-global-footer");
    if (kpHeader) {
      kpHeader.style.display = 'none';
      console.log('[Web Pivot]: KP Header hidden for Epic iframe.');
    }
    if (kpFooter) {
      kpFooter.style.display = 'none';
      console.log('[Web Pivot]: KP Footer hidden for Epic iframe.');
    }
    if (kpGlblFooter) {
      kpGlblFooter.style.display = 'none';
      console.log('[Web Pivot]: KP kpGlblFooter hidden for Epic iframe.');
    }

     hideP1P2Alerts();
  } catch (e) {
    console.error('[Web Pivot]: Error while disabling KP Header/Footer.', e);
  }
}
 const hideP1P2Alerts = () => {
  console.log("hideP1P2Alerts+++++++");
  try {
       const alertHeader = document.querySelector("#alerts-notification-placeholder-id");
       const bulletinAlerts = document.querySelector(".bulletinAlerts");

    if (alertHeader) {
      alertHeader.style.display = 'none';
      console.log('[Web Pivot]: P1 and P2 alerts hidden.');
    }
    if (bulletinAlerts) {
      bulletinAlerts.style.display = 'none';
      console.log('[Web Pivot]: P1 and P2 alerts hidden.');
    }
  } catch (e) {
    console.error('[Web Pivot]: Error while hidning P1 and P2 alerts.', e);
  }
}


const initializeWebPivotPage = () => {
  try {

   console.log("initializeWebPivotPage+++++++");

    const isSignedOn = /isSignedOn=true/.test(document.cookie);
    if (sessionStorage.getItem('isEpicMychartPage') === 'true' && isSignedOn) {

    console.log("initializeWebPivotPage inside if+++++++");
      hideKPHeaderFooter();
      hideProxyPicker();
      hideP1P2Alerts();
      sessionStorage.removeItem('isEpicMychartPage');
    }
  } catch (e) {
    console.error('[Web Pivot]: Error while hiding header, footer & proxypicker in iframe.', e);
    return false;
  }
};

const updateWebPivotContent = () => {
  if (typeof (APF) !== 'undefined') {
    APF.on("pageready", initializeWebPivotPage);
  } else {
    document.addEventListener('DOMContentLoaded', initializeWebPivotPage);
  }
}

const retrieveCookie = (cookieName) => {
  let cookie = {};
  document.cookie.split(';').forEach(function (el) {
    let [key, value] = el.split('=');
    cookie[key.trim()] = value;
  })
  return cookie[cookieName];
}

const isGMWPending = () => {
  try {
    const urlPath = window.location.pathname;
    const TASKHUB = "/task-hub";

    console.log("[Web Pivot]: Host URL: ", window.location.pathname);
    if (urlPath?.toLowerCase().includes(TASKHUB) || retrieveCookie("isGMWTasksPending")) {
      console.log("[Web Pivot]:Identified as GMW Page Flow...");

      return true;
    }

     hideP1P2Alerts();
    console.log("[Web Pivot]: Non GMW Page Flow...");

    return false;
  } catch (err) {
    console.error('[Web Pivot]: Error in isGMWPending.', err);
    console.log("[Web Pivot]: Non GMW Page Flow...");
    return false;
  }
}

 const deleteCookie = (name, path, domain)=> {
      console.log("All tasks are complete and clear isGMWTasksPending cookie");

      if (document.cookie.includes(name)) {
          document.cookie = name + "=; expires=Thu, 01 Jan 1970 00:00:00 UTC;" +
                    (domain ? "; domain=" + domain : "") +
                    (path ? "; path=" + path : "");
      } else {
          console.log("Cookie not found in document.cookie");
      }
  }





if (retrieveCookie("isGMWTasksPending") && !document.referrer) {

    deleteCookie('isGMWTasksPending', "/", ".kaiserpermanente.org");

    console.log("[Web Pivot]: isGMWTasksPending deleted.. ");
}
if (!isGMWPending()) {

  console.log("Non GMW Page Flow inside isGMWPending...");
  initWebPivotRedirect();
  initMYCRedirect();
  hideP1P2Alerts();
}

